### 4. **No Rate Limiting or Logging**
**Problem:** Failed admin attempts aren't logged, making it hard to detect attacks.

**Fix:** Add logging for security monitoring:
```javascript
function checkAdmin(req, res, next) {
  const adminHeader = req.headers['x-admin'];

  if (adminHeader && adminHeader.toLowerCase() === 'true') {
    next();
  } else {
    // Log failed attempts
    console.warn(`Failed admin access attempt from IP: ${req.ip}`);
    res.status(403).json({ error: 'Not admin' });
  }
}
```

### 5. **Hardcoded Secret Value**
**Problem:** Using a simple string 'true' as the secret is insecure.

**Fix:** If you must use a header-based approach (not recommended), at least use a proper secret:
```javascript
const ADMIN_SECRET = process.env.ADMIN_SECRET; // Store in environment variable

function checkAdmin(req, res, next) {
  if (req.headers['x-admin-secret'] === ADMIN_SECRET) {
    next();
  } else {
    res.status(403).json({ error: 'Not admin' });
  }
}
```

### 6. **Missing Additional Security Headers**
**Problem:** No protection against timing attacks or other common vulnerabilities.

**Fix:** Consider adding constant-time comparison for secrets:
```javascript
const crypto = require('crypto');

function constantTimeCompare(a, b) {
  return crypto.timingSafeEqual(
    Buffer.from(a, 'utf8'),
    Buffer.from(b, 'utf8')
  );
}
```

## Recommended Complete Solution

```javascript
function checkAdmin(req, res, next) {
  // 1. First check if user is authenticated (using proper auth middleware)
  if (!req.user) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // 2. Check admin role from properly authenticated user object
  if (req.user.role === 'admin') {
    next();
  } else {
    // 3. Log failed attempts for security monitoring
    console.warn(`Unauthorized admin access attempt by user: ${req.user.id}`);

    // 4. Return generic error message to avoid information leakage
    res.status(403).json({ error: 'Insufficient permissions' });
  }
}
```

